import Foundation

class AnalyticsDebugger {
    
    static let shared = AnalyticsDebugger()
    
    private init() {}
    
    func logAuthenticationFlow(userID: String, email: String, success: Bool) {
        let maskedEmail = maskEmail(email)
        NSLog("Auth Flow - UserID: \(userID), Email: \(maskedEmail), Success: \(success)")
    }
    
    func logAPICall(endpoint: String, requestPayload: [String: Any], responsePayload: [String: Any], success: Bool) {
        NSLog("API Call - Endpoint: \(endpoint), Request: \(maskSensitiveData(requestPayload)), Response: \(maskSensitiveData(responsePayload)), Success: \(success)")
    }
    
    func logUserDataChange(userID: String, changes: [String: Any]) {
        NSLog("User Data Change - UserID: \(userID), Changes: \(maskSensitiveData(changes))")
    }
    
    func logErrorCondition(userID: String?, error: Error) {
        let userInfo = userID != nil ? "UserID: \(userID!)" : "UserID: Unknown"
        NSLog("Error Condition - \(userInfo), Error: \(error.localizedDescription)")
    }
    
    private func maskEmail(_ email: String) -> String {
        let components = email.split(separator: "@")
        guard components.count == 2 else { return "Invalid Email" }
        let localPart = components[0]
        let domainPart = components[1]
        let maskedLocal = localPart.prefix(1) + String(repeating: "*", count: max(0, localPart.count - 2)) + localPart.suffix(1)
        return "\(maskedLocal)@\(domainPart)"
    }
    
    private func maskSensitiveData(_ data: [String: Any]) -> [String: Any] {
        var maskedData = data
        for key in data.keys {
            if key.lowercased().contains("password") || key.lowercased().contains("token") {
                maskedData[key] = "****"
            }
        }
        return maskedData
    }
}

